#!/usr/bin/env node
import { readFileSync } from 'node:fs';
import assert from 'node:assert/strict';
import { matchesKey } from '@mariozechner/pi-tui';

const cli = readFileSync(new URL('../src/cli.ts', import.meta.url), 'utf8');
const daemon = readFileSync(new URL('../pi/extensions/mi-daemon.mjs', import.meta.url), 'utf8');
const miExtension = readFileSync(new URL('../pi/extensions/mi.ts', import.meta.url), 'utf8');
const miAgentE2e = readFileSync(new URL('../scripts/test-mi-agent-e2e.mjs', import.meta.url), 'utf8');

assert.match(cli, /mi agents\s+Open mi agents live background agent view/, 'usage documents mi agents startup command and mi agents name');
assert.match(cli, /AssistantMessageComponent, getMarkdownTheme, getSelectListTheme, initTheme, UserMessageComponent/, 'CLI imports pi message components and theme');
assert.match(cli, /CombinedAutocompleteProvider, CURSOR_MARKER, Editor, matchesKey, ProcessTerminal, TUI, type Component, type Focusable, type SlashCommand/, 'CLI imports pi Editor, autocomplete provider, key matching, and pi-tui runtime for input and differential rendering');
assert.match(cli, /initTheme\(process\.env\.PI_THEME, false\)/, 'CLI initializes pi theme before rendering pi components');
assert.match(cli, /function renderPiUserMessage\(text: string, width: number\)[\s\S]*new UserMessageComponent\(text, getMarkdownTheme\(\)\)/, 'Mi renders user messages with pi UserMessageComponent');
assert.match(cli, /function renderPiAssistantMessage\(text: string, width: number\)[\s\S]*new AssistantMessageComponent\(\{ content: \[\{ type: 'text', text: trimmed \}\] \} as any, false, getMarkdownTheme\(\)\)/, 'Mi renders assistant messages with pi AssistantMessageComponent');
assert.match(cli, /while \(lines\.length > 0 && stripAnsi\(lines\[0\] \|\| ''\)\.trim\(\) === ''\) lines\.shift\(\)/, 'Mi removes assistant component marker-only leading blank lines');
assert.match(cli, /function renderMiTranscript\(transcript:[\s\S]*if \(body\.length > 0\) body\.push\(''\)/, 'main Mi TUI inserts one explicit blank line between transcript messages');
assert.match(cli, /function renderPiEditorText\(text: string, width: number, terminalRows: number\)[\s\S]*new Editor\(tui, piEditorTheme\(\)\)/, 'Mi renders input with pi Editor styling');
assert.match(cli, /async function miAgentsCommand\(\)/, 'cli defines mi agents view command');
assert.match(cli, /pollTimer\s*=\s*setInterval\(\(\) => \{[\s\S]*hasLiveWork[\s\S]*MI_IDLE_TASK_POLL_MS[\s\S]*void refresh\(\);[\s\S]*\}, MI_TASK_POLL_MS\)/, 'agent view polls live task state and backs off when idle');
assert.match(cli, /function taskLayoutSignature\(task: MiTask\)[\s\S]*taskSection\(task\)[\s\S]*forceFullRender = beforeLayoutSignature !== tasks\.map\(taskLayoutSignature\)/, 'agent view only forces full renders for layout changes, not live progress updates');
assert.match(cli, /const MI_TASK_POLL_MS = Number\(process\.env\.MI_TASK_POLL_MS \|\| 3000\)/, 'agent view uses a bounded active polling cadence');
assert.match(cli, /const MI_IDLE_TASK_POLL_MS = Number\(process\.env\.MI_IDLE_TASK_POLL_MS \|\| 10000\)/, 'agent view backs off polling when idle');
assert.match(cli, /const MI_AGENT_CLOCK_MS = Number\(process\.env\.MI_AGENT_CLOCK_MS \|\| 1000\)/, 'agent view uses a local clock redraw for elapsed time labels');
assert.match(cli, /const PI_LOADER_INTERVAL_MS = 80/, 'Mi defines pi loader default interval');
assert.match(cli, /const MI_AGENT_ANIMATION_MS = Number\(process\.env\.MI_AGENT_ANIMATION_MS \|\| 250\)/, 'agent view uses a lower default animation cadence than active pi chat');
assert.match(cli, /readSessionTailSync\(sessionFile\)/, 'agent view reads session tails instead of whole JSONL files');
assert.match(cli, /const MI_SESSION_ACTIVITY_REFRESH_MS = Number\(process\.env\.MI_SESSION_ACTIVITY_REFRESH_MS \|\| 1000\)/, 'agent view throttles active session activity parsing while spinner frames render');
assert.match(cli, /sessionActivityStepsCache[\s\S]*Date\.now\(\) - cached\.at < MI_SESSION_ACTIVITY_REFRESH_MS/, 'agent view caches parsed activity between spinner frames');
assert.match(cli, /function readSessionFinalOutput\(sessionFile: string, options: \{ full\?: boolean \} = \{\}\)[\s\S]*outputs\.push\(text\)[\s\S]*if \(options\.full\) return outputs\.join\('\\n\\n'\)[\s\S]*return outputs\.at\(-1\) \|\| ''/, 'agent view skips queued-goal inactive sentinel when showing session final output');
assert.match(cli, /function readSessionFullTranscript\(sessionFile: string\)[\s\S]*role !== 'user' && role !== 'assistant'[\s\S]*items\.push\(\{ role, text \}\)[\s\S]*return items/, 'agent view reads full user/assistant transcript for full output mode');
assert.match(cli, /function taskFinalOutput\(task: MiTask, options: \{ full\?: boolean \} = \{\}\)[\s\S]*options\.full \? \(sessionText \|\| text\) : \(text \|\| sessionText\)/, 'full output mode prefers the full session assistant text over stored task text');
assert.match(cli, /function sanitizeVisibleAssistantText\(text: string\)[\s\S]*<thinking>[\s\S]*?<\\\/thinking>[\s\S]*<think>[\s\S]*?<\\\/think>[\s\S]*\(\?:thinking\|reasoning\)/, 'agent view strips leaked thinking/reasoning blocks from visible assistant text');
assert.match(cli, /function taskDisplayText\(task: MiTask\)[\s\S]*sanitizeVisibleAssistantText\(task\.text \|\| ''\)[\s\S]*!isNonFinalAssistantText\(text\)/, 'agent view sanitizes persisted task text and skips queued-goal inactive sentinel');
assert.match(cli, /function textFromSessionMessage\(message: any\)[\s\S]*typeof content === 'string'\) return sanitizeVisibleAssistantText\(content\)[\s\S]*part\?\.type === 'text'[\s\S]*part\?\.type === 'toolCall'[\s\S]*sanitizeVisibleAssistantText/, 'agent view excludes structured thinking parts when reading session messages');
assert.doesNotMatch(cli, /part\?\.type === 'thinking' \? `thinking:/, 'session message extraction must not turn thinking parts into visible final text');
assert.match(cli, /miTranscriptRenderCache/, 'main Mi TUI caches transcript rendering between spinner frames');
assert.match(cli, /const MI_WORKING_RENDER_MS = Number\(process\.env\.MI_WORKING_RENDER_MS \|\| PI_LOADER_INTERVAL_MS\)/, 'main Mi TUI uses pi loader spinner cadence');
assert.match(cli, /workingFrame = \(workingFrame \+ 1\) % PI_SPINNER_FRAMES\.length/, 'main Mi TUI advances working spinner by frame count instead of wall-clock jumps');
assert.match(cli, /inputMode: 'normal' \| 'new-name' \| 'new-prompt' \| 'reply'/, 'agent view supports new task and explicit inline reply modes');
assert.match(cli, /let replyTarget: MiTask \| undefined/, 'agent view tracks reply targets');
assert.match(cli, /inputMode === 'normal' && text\.length > 0 && !text\.startsWith\('\/'\)[\s\S]*replyTarget = selectedTask\(\);[\s\S]*inputMode = replyTarget \? 'reply' : 'normal';[\s\S]*Select a task or use \/new/, 'typing normal text replies to the selected task; new tasks require /new');
assert.match(cli, /function agentInputVisibleLines\(width: number, maxLines: number\)/, 'agent view wraps input across visible lines like main Mi');
assert.match(cli, /fgAccent\(truncateText\('mi agents', width\)\) \+ fgLightGrey\(truncateText\(`  \$\{status\}`/, 'agent view places status next to mi agents title');
assert.match(cli, /const footerLines = \[[\s\S]*\.\.\.inputLines\.map\(\(line\) => truncateText\(line, width\)\)[\s\S]*agentModelWithThinking\(\), width\)\.padStart\(width\)/, 'agent view renders pi editor footer with right-aligned model');
assert.match(cli, /const maxInputLines = Math\.max\(1, height - 4\)[\s\S]*const inputLines = rawInputLines\.length > maxInputLines \? rawInputLines\.slice\(-maxInputLines\) : rawInputLines[\s\S]*const contentHeight = Math\.max\(0, height - footerLines\.length\)/, 'agent view reserves bottom space for a prompt that grows upward without overflowing the terminal');
assert.match(cli, /while \(lines\.length < contentHeight\) lines\.push\(''\);\n    lines\.push\(\.\.\.footerLines\)/, 'agent view places footer after full detail content for scrollback');
assert.match(cli, /startPiTuiScreen\(new FunctionScreen\(renderAgentLines, onData\), \{ alternateScreen: true \}\)/, 'mi agents uses alternate screen so stale scrollback rows cannot look like duplicate tasks');
assert.match(cli, /stale rows cannot remain in terminal scrollback/, 'agent view documents why alternate screen is needed');
assert.match(cli, /const maxCollapsedActivityLines = Math\.max\(1, Math\.min\(12, Math\.floor\(contentHeight \* 0\.5\)\)\)[\s\S]*const collapsedDetailBudget = \(\) => Math\.max\(1, Math\.min\(maxCollapsedActivityLines, remainingContentLines\(\)\)\)/, 'agent view caps collapsed activity to the visible info pane while allowing more final output');
assert.match(cli, /if \(lines\.length > contentHeight\) lines\.splice\(contentHeight\);[\s\S]*lines\.push\(\.\.\.footerLines\)/, 'agent view keeps the input footer visible in collapsed mode');
assert.match(cli, /activity\.map\(\(line\) => truncateText\(line, width\)\)\.slice\(-collapsedDetailBudget\(\)\)/, 'agent view shows newest collapsed activity');
assert.match(cli, /function renderFullOutputLines\(task: MiTask, fallbackText: string, width: number\)[\s\S]*const transcript = sessionFile && !isTaskActive\(task\) && !isStoppedPiSessionWithoutFinal\(task\) \? readSessionFullTranscript\(sessionFile\) : \[\][\s\S]*item\.role === 'user' \? renderPiUserMessage\(item\.text, width\) : renderPiLastOutputMessage\(item\.text, width\)[\s\S]*const outputLines = renderFullOutputLines\(task, fullLastOutput \|\| 'No result yet\.', width\)[\s\S]*terminal\/tmux scrollback[\s\S]*lines\.push\(\.\.\.outputLines\)/, 'full last output mode renders full transcript for completed tasks and avoids stale transcript output for active tasks');
assert.match(cli, /const sessionFullTranscriptCache = new Map[\s\S]*cached\.size === stats\.size && cached\.mtimeMs === stats\.mtimeMs/, 'full last output mode caches parsed session transcript between keypresses');
assert.match(cli, /const fullOutputRenderCache = new Map[\s\S]*cached && cached\.size === size && cached\.mtimeMs === mtimeMs[\s\S]*return cached\.lines/, 'full last output mode caches rendered transcript lines between keypresses');
assert.match(cli, /function requestRender\(force = false\)[\s\S]*differential renders for spinner\/input updates to avoid flicker[\s\S]*force=true for structural list changes[\s\S]*requestRender\?\.\(force\)/, 'mi agents avoids full-frame spinner flicker while keeping force redraw available for structural changes');
assert.doesNotMatch(cli, /WHITE_CURSOR|RESET_CURSOR|\\x1b\]12|\\x1b\]112/, 'Mi does not override terminal cursor color; pi-tui owns cursor behavior');
assert.match(cli, /function startPiTuiScreen\(component: Component & Focusable, options: \{ alternateScreen\?: boolean; clearScreen\?: boolean \} = \{\}\)[\s\S]*new ProcessTerminal\(\)[\s\S]*new TUI\(terminal\)/, 'Mi screens let pi-tui own default cursor behavior');
assert.match(cli, /\?1049h\\x1b\[2J\\x1b\[3J\\x1b\[H/, 'alternate-screen startup clears stale scrollback so old task rows cannot look duplicated');
assert.match(cli, /else process\.stdout\.write\('\\x1b\[3J'\)/, 'normal-screen TUI startup also clears previous stale scrollback');
assert.match(cli, /const DISABLE_MOUSE_TRACKING_SEQUENCE = '\\x1b\[\?1000l\\x1b\[\?1002l\\x1b\[\?1003l\\x1b\[\?1006l\\x1b\[\?1015l'/, 'Mi has a local mouse tracking reset for tmux wheel scrollback');
assert.match(cli, /Reset stale mouse tracking from prior full-screen apps before pi-tui starts[\s\S]*process\.stdout\.write\(DISABLE_MOUSE_TRACKING_SEQUENCE\)[\s\S]*tui\.start\(\)/, 'Mi disables stale mouse tracking before starting its TUI');
assert.match(cli, /Mi does not handle mouse input; keep it disabled so tmux mouse-wheel scrollback works\.[\s\S]*process\.stdout\.write\(DISABLE_MOUSE_TRACKING_SEQUENCE\)[\s\S]*if \(options\.alternateScreen\)/, 'Mi disables mouse tracking again during TUI cleanup');
assert.match(cli, /const PI_SLASH_COMMANDS = \['\/model'[\s\S]*'\/resume'[\s\S]*'\/quit'[\s\S]*'\/mi'/, 'agent view has pi-ordered slash command candidates plus mi overrides');
assert.match(cli, /function createPiSlashAutocompleteProvider\(commands = PI_SLASH_COMMANDS\)[\s\S]*new CombinedAutocompleteProvider\(slashCommands, process\.cwd\(\)\)/, 'Mi slash autocomplete uses pi-tui CombinedAutocompleteProvider');
assert.match(cli, /agentEditor\.setAutocompleteProvider\(createPiSlashAutocompleteProvider\(\)\)/, 'agent view lets the real pi Editor render slash command autocomplete');
assert.match(cli, /inputEditor\.setAutocompleteProvider\(createPiSlashAutocompleteProvider\(\[[^\]]*'\/compact'[^\]]*'\/quit'[^\]]*\]\)\)/, 'main Mi input also uses pi-style slash command autocomplete');
assert.doesNotMatch(cli, /function editorAutocompletePage|editorAutocompletePage\(/, 'Mi does not override pi Editor PageUp/PageDown behavior for slash autocomplete');
assert.match(cli, /function splitTerminalInput\(data: string\)[\s\S]*\\x1b\\\[5\(\?:;\\d\+\)\?~[\s\S]*\\x1b\\\[6\(\?:;\\d\+\)\?~/, 'Mi splits combined terminal key chunks before dispatch');
assert.match(cli, /const keyParts = splitTerminalInput\(data\);[\s\S]*for \(const keyPart of keyParts\) onData\(keyPart\)/, 'mi agents dispatches combined PageUp/PageDown chunks one key at a time');
assert.match(cli, /isPageUpKey\(data\) \|\| isPageDownKey\(data\)[\s\S]*!inputBuffer[\s\S]*moveAgentListSelection\(isPageUpKey\(data\) \? -5 : 5\)[\s\S]*handleAgentEditorInput\(data\)/, 'agent view pages the task list with PageUp/PageDown when input is empty, otherwise routes keys to the pi Editor');
assert.match(cli, /isPageUpKey\(data\) \|\| isPageDownKey\(data\) \|\| isUpKey\(data\) \|\| isDownKey\(data\)[\s\S]*inputEditor\.handleInput\(data\)/, 'main Mi routes navigation keys to the pi Editor like pi');
assert.doesNotMatch(cli, /function slashCommandSuggestionLines|function slashFuzzyScore|let slashSelected|function moveSlashSelection|autocompleteSlashCommand/, 'Mi no longer hand-renders slash autocomplete');
assert.doesNotMatch(cli, /\.\.\.slashSuggestionLines|slashMatches\.slice\(0, 6\)\.join\('  '\)/, 'slash commands are rendered by pi Editor, not inline Mi hints');
assert.match(cli, /function clearAgentInputModeIfEmpty\(\)/, 'agent view exits reply input mode when reply text is deleted');
assert.match(cli, /const agentEditor = new Editor\(agentEditorTui, piEditorTheme\(agentThinkingLevel\)\)/, 'agent view uses the real pi Editor with thinking-colored input styling');
assert.match(cli, /function handleAgentEditorInput\(data: string\)[\s\S]*agentEditor\.handleInput\(data\)/, 'agent view delegates text input and paste handling to the pi Editor');
assert.match(cli, /new ProcessTerminal\(\)/, 'agent view delegates bracketed paste enablement to pi-tui ProcessTerminal');
assert.match(cli, /tui\?\.stop\(\)/, 'agent view delegates bracketed paste cleanup to pi-tui ProcessTerminal');
assert.match(cli, /\(inputMode === 'reply' \|\| inputMode === 'mi-chat'\) && inputBuffer\.length === 0[\s\S]*inputMode = 'normal'[\s\S]*replyTarget = undefined/, 'empty reply input unselects reply target');
assert.match(cli, /clearAgentInputModeIfEmpty\(\)/, 'backspace invokes empty reply input cleanup');
assert.match(cli, /function cycleAgentThinking\(\)/, 'agent view supports Shift+Tab model thinking changes');
assert.match(cli, /const THINKING_LEVELS: ThinkingLevel\[\] = \['off', 'minimal', 'low', 'medium', 'high', 'xhigh'\]/, 'mi and mi agents share the full pi thinking level cycle');
assert.match(cli, /cycleAgentThinking\(\)[\s\S]*THINKING_LEVELS\.indexOf\(agentThinkingLevel \|\| 'low'\)[\s\S]*agentThinkingLevel = THINKING_LEVELS/, 'mi agents Shift+Tab cycles all thinking levels');
assert.match(cli, /async function cycleThinking\(\)[\s\S]*THINKING_LEVELS\.includes\(miState\?\.thinkingLevel as ThinkingLevel\)[\s\S]*const next = THINKING_LEVELS/, 'mi Shift+Tab cycles all thinking levels');
assert.match(cli, /matchesKey\(data, 'shift\+tab'\)[\s\S]*cycleAgentThinking\(\)/, 'agent view maps Shift+Tab to model thinking switch through pi key matching');
assert.doesNotMatch(cli, /status = `Agent (?:model|tier)/, 'agent view does not put model changes in the help/status line');
assert.match(cli, /async function applyAgentPiCycle\(text: string\)/, 'agent view supports pi-cycle model shortcuts for new tasks and replies');
assert.match(cli, /async function runAgentSlashCommand\(value: string\)/, 'agent view supports slash commands in input');
assert.match(cli, /const PI_SLASH_COMMANDS = \[[^\]]*'\/plan'[^\]]*'\/marker'[^\]]*'\/end'[^\]]*\]/, 'agent view autocompletes /plan, /marker, and /end');
assert.match(cli, /const MI_BACKGROUND_SLASH_COMMANDS = new Set\(Object\.entries\(MI_COMMAND_CLASSIFICATIONS\)\.filter\(\(\[, info\]\) => info\.class === 'background-task'\)/, 'agent view starts background-task classified commands without opening Pi');
assert.match(miAgentE2e, /\/plan is a full Mi agents workflow command[\s\S]*message === '\/plan design safe change'[\s\S]*message === 'what tests should cover this\?'[\s\S]*message === 'go implement that plan'/, 'mi agents e2e covers the full /plan workflow: start, refine, and go on the same worker');
assert.match(cli, /const MI_NATIVE_AGENT_SLASH_COMMANDS = new Set\(Object\.entries\(MI_COMMAND_CLASSIFICATIONS\)\.filter\(\(\[, info\]\) => info\.class === 'worker-forward'\)/, 'agent view handles worker-forward slash commands natively');
assert.match(cli, /async function sendNativeAgentSlashCommand\(value: string\)[\s\S]*const isMarker = command === '\/marker'[\s\S]*const waitForDone = command === '\/end'[\s\S]*Sending \$\{command\} to selected task[\s\S]*type: 'continue_worker'[\s\S]*background: !waitForDone[\s\S]*preserveStatus: true[\s\S]*if \(waitForDone\) status = 'Increment summarized and marker advanced'/, 'native task slash commands show extension status above input and preserve task state');
assert.match(cli, /MI_NATIVE_AGENT_SLASH_COMMANDS\.has\(slashCommandName\(value\)\)[\s\S]*sendNativeAgentSlashCommand\(value\)/, 'runAgentSlashCommand dispatches native task slash commands');
assert.doesNotMatch(cli, /else if \(data === 'n' \|\| data\.startsWith\('n'\)\)/, 'n no longer creates new tasks; use /new');
assert.match(cli, /const name = explicitName \|\| taskNameFromPrompt\(turn\.body\)/, 'new task prompts get an automatic task name');
assert.match(cli, /let optimisticTasks: MiTask\[] = \[]/, 'agent view tracks optimistic tasks while daemon startup is pending');
assert.match(cli, /optimisticTasks = optimisticTasks\.filter\(\(optimistic\) => !listedTasks\.some/, 'agent refresh preserves optimistic tasks until real daemon task appears');
assert.match(cli, /const optimisticTask: MiTask = \{[\s\S]*status: 'queued'[\s\S]*progress: turn\.body[\s\S]*optimisticTasks = \[optimisticTask, \.\.\.optimisticTasks\][\s\S]*tasks = \[optimisticTask, \.\.\.tasks\]/, 'new agent tasks appear immediately before daemon startup returns');
assert.match(cli, /optimisticTask\.id = result\.taskId \|\| optimisticTask\.id[\s\S]*optimisticTask\.status = 'running'/, 'optimistic new agent row is updated from daemon result instead of disappearing');
assert.match(cli, /optimisticTask\.status = 'error'[\s\S]*optimisticTask\.error = error instanceof Error/, 'failed new agent startup leaves an error row visible');
assert.doesNotMatch(cli, /optimisticTasks = optimisticTasks\.filter\(\(task\) => task\.id !== optimisticTask\.id\)/, 'new agent optimistic row is not removed until real task appears in refresh');
assert.match(cli, /agentSubmitting = true;[\s\S]*void sendTaskSocketRequest\(\{ type: 'run_worker'[\s\S]*\.finally\(\(\) => \{\n          agentSubmitting = false;/, 'new agent task creation is fire-and-forget after optimistic render');
assert.match(cli, /Timed out waiting for Mi main[\s\S]*rm\(MI_SOCKET_PATH, \{ force: true \}\)/, 'cli removes stale Mi socket and restarts daemon on timeout');
assert.match(cli, /agentEditor\.onSubmit = \(value\) => \{[\s\S]*void submitAgentInput\(\)/, 'agent input submits through the pi Editor onSubmit path');
assert.match(cli, /value === '\/quit'[\s\S]*close\(\)/, 'agent view slash quit exits');
assert.match(cli, /'\/goal': \{ class: 'worker-forward'/, 'agent view classifies /goal as worker-forward');
assert.match(cli, /MI_NATIVE_AGENT_SLASH_COMMANDS\.has\(slashCommandName\(value\)\)[\s\S]*sendNativeAgentSlashCommand\(value\)/, 'agent view forwards worker-forward commands to selected worker');
assert.match(cli, /let btwAnswer = ''/, 'agent view stores /mi answers for display');
assert.match(cli, /let miChatTask: MiTask \| undefined/, 'agent view tracks the active /mi chat task');
assert.match(cli, /async function askMiAboutTask\(task: MiTask, question: string\)[\s\S]*sendToMiMain\(\[[\s\S]*Selected task context:/, 'agent view /mi uses Mi main to answer only about selected task context');
assert.match(cli, /value\.startsWith\('\/mi'\)[\s\S]*inputMode = 'mi-chat'[\s\S]*\^C end/, 'agent view /mi stays in chat mode after the first answer');
